// RektSky B5 - ChestStealer.java (S2D silent chest detection)
// Full source — handles S2DPacketOpenWindow for silent chest stealing
public class ChestStealer extends Module {
    private Container inventory;
    private IInventory iinventory;
    private Integer windowId;
    public BooleanSetting chestCheck = new BooleanSetting("ChestCheck", true);

    @Override
    public void onEvent(Event e2) {
        if (e2 instanceof PacketReceiveEvent && this.slientSetting.getValue().booleanValue()) {
            if (((PacketReceiveEvent) e2).getPacket() instanceof S2DPacketOpenWindow) {
                S2DPacketOpenWindow packet = (S2DPacketOpenWindow) ((PacketReceiveEvent) e2).getPacket();
                // Check if the window title says "Chest"
                String title = packet.getWindowTitle().getUnformattedTextForChat();
                if (title.equalsIgnoreCase("chest") || !this.chestCheck.getValue().booleanValue()) {
                    // Cancel the vanilla open — GUI never shows
                    ((PacketReceiveEvent) e2).setCanceled(true);

                    // Store chest data silently
                    this.iinventory = new InventoryBasic(
                        packet.getWindowTitle(), packet.getSlotCount());
                    this.inventory = new ContainerChest(
                        mc.thePlayer.inventory, this.iinventory, mc.thePlayer);
                    this.windowId = packet.getWindowId();
                }
            }

            // S30 fills the silent chest with items
            if (((PacketReceiveEvent) e2).getPacket() instanceof S30PacketWindowItems) {
                S30PacketWindowItems packet = (S30PacketWindowItems) ((PacketReceiveEvent) e2).getPacket();
                if (this.windowId != null && packet.getWindowID() == this.windowId.intValue()) {
                    this.inventory.putStacksInSlots(packet.getItemStacks());
                    ((PacketReceiveEvent) e2).setCanceled(true);
                }
            }
        }
    }
}

