package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import net.minecraft.util.IChatComponent;
import java.io.IOException;

public class S2DPacketOpenWindow implements Packet<INetHandlerPlayClient> {
    private int windowId;
    private String inventoryType;
    private IChatComponent windowTitle;
    private int slotCount;
    private int entityId;  // -1 if not horse

    public S2DPacketOpenWindow() {}
    public S2DPacketOpenWindow(int windowIdIn, String invTypeIn, IChatComponent titleIn,
                                int slotCountIn, boolean useProvidedTitle, int entityIdIn) {
        this.windowId = windowIdIn;
        this.inventoryType = invTypeIn;
        this.windowTitle = titleIn;
        this.slotCount = slotCountIn;
        this.entityId = entityIdIn;
    }

    public void processPacket(INetHandlerPlayClient handler) { handler.handleOpenWindow(this); }
    public int getWindowId() { return this.windowId; }
    public String getGuiId() { return this.inventoryType; }
    public IChatComponent getWindowTitle() { return this.windowTitle; }
    public int getSlotCount() { return this.slotCount; }
    public int getEntityId() { return this.entityId; }
}
